-- ============================================
-- LIMPIEZA Y RESETEO DE SECUENCIA
-- ============================================

-- Eliminar todos los registros
DELETE FROM comprobante_venta;

-- Resetear la secuencia en PostgreSQL
SELECT setval(pg_get_serial_sequence('comprobante_venta', 'id_comprobante_venta'), 1, false);

-- ============================================
-- INSERCIÓN DE DATOS (manteniendo IDs manuales)
-- ============================================

































-- ============================================
-- VERIFICACIÓN
-- ============================================
SELECT COUNT(*) AS total_registros FROM comprobante_venta;
SELECT * FROM comprobante_venta ORDER BY id_comprobante_venta;